def gen(rng, size):
    n = max(1, min(size, 100))
    a = [rng.randint(-50, 50)]
    for _ in range(n - 1):
        a.append(rng.randint(-50, 50) if rng.random() < 0.7 else None)
    if rng.random() < 0.5:
        b = list(a)
    else:
        b = list(a)
        if b:
            idx = rng.randrange(len(b))
            if b[idx] is None:
                b[idx] = rng.randint(-50, 50)
            else:
                b[idx] = None if rng.random() < 0.5 else b[idx] + 1
    if not b:
        b = [rng.randint(-50, 50)]
    return [a, b]

